// --- CONFIGURAZIONE ---
u_min := 0;
u_max := 6.28318; // 2*PI
v_min := 0;
v_max := 6.28318;
steps := 350;

// --- CODICE SHADER ---

// Parametri Geometrici
float scale = 3.0; 
float r = 0.4; // Raggio del tubo

// --- 1. EQUAZIONE CANONICA NODO A OTTO (4_1) ---
// Questa è la forma parametrica standard che garantisce la topologia corretta.
// x = (2 + cos(2u)) * cos(3u)
// y = (2 + cos(2u)) * sin(3u)
// z = sin(4u)

// Modulazione del raggio nel piano
float R_base = 2.5; // Allarga il buco centrale
float mod_r = 1.0 * cos(2.0 * u);

float r_xy = R_base + mod_r;

// Posizione Curva
vec3 Curve = vec3(
    r_xy * cos(3.0 * u),
    r_xy * sin(3.0 * u),
    1.2 * sin(4.0 * u) // 1.2 estende la Z per evitare collisioni nei sovrappassi
);

// --- 2. DERIVATA PRIMA (Velocità Analitica) ---
// Calcolata per ottenere tangenti perfette
// R' = -2 * sin(2u)
float dr = -1.0 * 2.0 * sin(2.0 * u);

// Derivate parziali
// dX = r'cos(3u) - r*3sin(3u)
// dY = r'sin(3u) + r*3cos(3u)
// dZ = 1.2 * 4 * cos(4u)

vec3 dC = vec3(
    dr * cos(3.0 * u) - r_xy * 3.0 * sin(3.0 * u),
    dr * sin(3.0 * u) + r_xy * 3.0 * cos(3.0 * u),
    4.8 * cos(4.0 * u)
);

vec3 Tangent = normalize(dC);

// --- 3. CALCOLO FRAME STABILE (Global Up Method) ---
// INVECE di guardare il centro (che causa strozzature),
// usiamo l'asse Z come riferimento stabile.
vec3 Up = vec3(0.0, 0.0, 1.0);

// Calcoliamo la Binormale come prodotto vettoriale tra Tangente e Su.
// Questo crea un vettore orizzontale perpendicolare alla curva.
vec3 Binorm = cross(Tangent, Up);

// Se la tangente è quasi verticale, usiamo l'asse Y come fallback per evitare glitch
if (length(Binorm) < 0.001) {
    Binorm = cross(Tangent, vec3(0.0, 1.0, 0.0));
}
Binorm = normalize(Binorm);

// La Normale è il terzo vettore ortogonale
vec3 Norm = cross(Binorm, Tangent);
Norm = normalize(Norm);

// --- 4. COSTRUZIONE TUBO ---
float tube_cos = r * cos(v);
float tube_sin = r * sin(v);

// Combina tutto
vec3 pos = Curve + (tube_cos * Norm + tube_sin * Binorm);

// Scala finale per adattarlo allo schermo
return vec4(pos * 0.35, 0.0);
